const data = $input.first().json;
const listings = data.listings || [];
const processedAt = new Date().toISOString();

const parsed = listings.map(listing => {
  // Extract price from text like "R 1 250 000" or "R1250000"
  const priceText = listing.price || '';
  const priceMatch = priceText.replace(/[\s,]/g, '').match(/R?([\d]+)/);
  const price = priceMatch ? parseFloat(priceMatch[1]) : 0;

  // Extract bedroom count from title/description
  const bedroomMatch = (listing.title + ' ' + listing.description).match(/(\d+)\s*(?:bed|bedroom|br)/i);
  const bedrooms = bedroomMatch ? parseInt(bedroomMatch[1]) : 0;

  // Extract bathroom count
  const bathroomMatch = (listing.title + ' ' + listing.description).match(/(\d+)\s*(?:bath|bathroom|ba)/i);
  const bathrooms = bathroomMatch ? parseInt(bathroomMatch[1]) : 0;

  // Determine property type
  const text = (listing.title + ' ' + listing.description).toLowerCase();
  let propertyType = 'unknown';
  if (text.includes('apartment') || text.includes('flat')) propertyType = 'apartment';
  else if (text.includes('townhouse') || text.includes('town house')) propertyType = 'townhouse';
  else if (text.includes('plot') || text.includes('land')) propertyType = 'plot';
  else if (text.includes('house') || text.includes('home')) propertyType = 'house';

  return {
    listing_id: `fb_market_${listing.marketplace_id || listing.id}`,
    title: listing.title || 'Facebook Marketplace Property',
    price: price,
    price_currency: 'ZAR',
    bedrooms: bedrooms,
    bathrooms: bathrooms,
    property_type: propertyType,
    suburb: listing.location?.suburb || '',
    city: listing.location?.city || listing.location || '',
    province: listing.location?.province || '',
    url: `https://www.facebook.com/marketplace/item/${listing.marketplace_id}`,
    source: 'facebook_marketplace',
    description: listing.description || '',
    seller_name: listing.seller?.name || '',
    seller_profile: listing.seller?.profile_url || '',
    images: listing.images || [],
    scraped_at: processedAt,
    raw_price_text: priceText,
    status: 'active'
  };
});

// Filter out listings with no price or clearly not property
const valid = parsed.filter(p => p.price > 0 && p.price < 50000000);

return valid.map(p => ({ json: p }));

